/**
 * Inspection Task Controller
 *
 * Tasks are AUTO-GENERATED by inspection.controller `complete` for items
 * flagged major/critical. This controller surfaces the maintenance-worker
 * workflow: list mine, take one in progress, upload proof photos, complete.
 *
 * Photo upload is handled by a separate endpoint via multer (see routes).
 */
const { query } = require('../database/connection');
const { logger } = require('../utils/logger');

const VALID_STATUS = ['pending', 'assigned', 'in_progress', 'completed', 'cancelled', 'overdue'];
const VALID_PRIORITY = ['low', 'medium', 'high', 'critical', 'emergency'];

const list = async (req, res) => {
  try {
    const { status, priority, assignee_id, mine, overdue, limit = 50, offset = 0 } = req.query;
    const clauses = [];
    const params = [];
    const push = (clause, v) => { params.push(v); clauses.push(clause.replace('??', `$${params.length}`)); };

    if (status)    push('t.status = ??', status);
    if (priority)  push('t.priority = ??', priority);
    if (assignee_id) push('t.assignee_id = ??', assignee_id);
    if (mine === 'true' && req.user?.id) push('t.assignee_id = ??', req.user.id);
    if (overdue === 'true') clauses.push(`t.due_date < CURRENT_DATE AND t.status NOT IN ('completed','cancelled')`);

    const where = clauses.length ? `WHERE ${clauses.join(' AND ')}` : '';
    const lim = Math.min(parseInt(limit, 10) || 50, 200);
    const off = parseInt(offset, 10) || 0;

    const r = await query(
      `SELECT t.*,
              i.inspection_number,
              a.name AS accommodation_name,
              u.first_name || ' ' || u.last_name AS assignee_name
       FROM inspection_tasks t
       LEFT JOIN inspections i ON t.inspection_id = i.id
       LEFT JOIN accommodations a ON i.accommodation_id = a.id
       LEFT JOIN users u ON t.assignee_id = u.id
       ${where}
       ORDER BY
         CASE t.priority
           WHEN 'emergency' THEN 1 WHEN 'critical' THEN 2 WHEN 'high' THEN 3
           WHEN 'medium' THEN 4 WHEN 'low' THEN 5
         END,
         t.due_date ASC NULLS LAST
       LIMIT $${params.length + 1} OFFSET $${params.length + 2}`,
      [...params, lim, off]
    );
    res.json({ success: true, data: r.rows, pagination: { limit: lim, offset: off } });
  } catch (err) {
    logger.error('[task.list]', err);
    res.status(500).json({ success: false, message: 'Feladatok lekérési hiba' });
  }
};

const getById = async (req, res) => {
  try {
    const [taskR, photosR] = await Promise.all([
      query(
        `SELECT t.*,
                i.inspection_number,
                a.name AS accommodation_name,
                u.first_name || ' ' || u.last_name AS assignee_name
         FROM inspection_tasks t
         LEFT JOIN inspections i ON t.inspection_id = i.id
         LEFT JOIN accommodations a ON i.accommodation_id = a.id
         LEFT JOIN users u ON t.assignee_id = u.id
         WHERE t.id = $1`,
        [req.params.id]
      ),
      query(
        `SELECT * FROM task_completion_photos WHERE task_id = $1 ORDER BY created_at`,
        [req.params.id]
      ),
    ]);
    if (taskR.rows.length === 0) {
      return res.status(404).json({ success: false, message: 'Feladat nem található' });
    }
    res.json({ success: true, data: { ...taskR.rows[0], photos: photosR.rows } });
  } catch (err) {
    logger.error('[task.getById]', err);
    res.status(500).json({ success: false, message: 'Hiba' });
  }
};

/** PATCH /api/v1/inspection-tasks/:id — assignment + status transitions */
const update = async (req, res) => {
  try {
    const {
      assignee_id, due_date, status, priority,
      title, description, completion_notes,
      estimated_cost, actual_cost,
    } = req.body;

    if (status && !VALID_STATUS.includes(status)) {
      return res.status(400).json({ success: false, message: `status egyike: ${VALID_STATUS.join(', ')}` });
    }
    if (priority && !VALID_PRIORITY.includes(priority)) {
      return res.status(400).json({ success: false, message: `priority egyike: ${VALID_PRIORITY.join(', ')}` });
    }

    // Transition timestamps:
    // - new assignee_id → stamp assigned_at + auto-set status='assigned' if pending
    // - status='completed' → stamp completed_at
    const r = await query(
      `UPDATE inspection_tasks SET
         assignee_id = COALESCE($1, assignee_id),
         assigned_at = CASE WHEN $1 IS NOT NULL AND assignee_id IS DISTINCT FROM $1 THEN NOW() ELSE assigned_at END,
         due_date = COALESCE($2::DATE, due_date),
         status = COALESCE(
           $3,
           CASE WHEN $1 IS NOT NULL AND status = 'pending' THEN 'assigned' ELSE status END
         ),
         priority = COALESCE($4, priority),
         title = COALESCE($5, title),
         description = COALESCE($6, description),
         completion_notes = COALESCE($7, completion_notes),
         completed_at = CASE WHEN $3 = 'completed' THEN NOW() ELSE completed_at END,
         estimated_cost = COALESCE($8, estimated_cost),
         actual_cost = COALESCE($9, actual_cost),
         updated_at = NOW()
       WHERE id = $10
       RETURNING *`,
      [assignee_id, due_date, status, priority, title, description, completion_notes,
       estimated_cost, actual_cost, req.params.id]
    );
    if (r.rows.length === 0) {
      return res.status(404).json({ success: false, message: 'Feladat nem található' });
    }
    res.json({ success: true, data: r.rows[0] });
  } catch (err) {
    logger.error('[task.update]', err);
    res.status(500).json({ success: false, message: 'Feladat frissítési hiba' });
  }
};

/** POST /api/v1/inspection-tasks/:id/verify — admin verifies completed task */
const verify = async (req, res) => {
  try {
    const r = await query(
      `UPDATE inspection_tasks SET
         completion_verified = true,
         verified_by = $1,
         updated_at = NOW()
       WHERE id = $2 AND status = 'completed'
       RETURNING *`,
      [req.user?.id || null, req.params.id]
    );
    if (r.rows.length === 0) {
      return res.status(409).json({
        success: false,
        message: 'Csak befejezett feladat ellenőrizhető',
      });
    }
    res.json({ success: true, data: r.rows[0] });
  } catch (err) {
    logger.error('[task.verify]', err);
    res.status(500).json({ success: false, message: 'Hiba' });
  }
};

module.exports = { list, getById, update, verify };
